sys_script_include.script:
var IDPScorecardEngine = Class.create();
IDPScorecardEngine.prototype = {
    initialize: function() {
        this.TABLE_SCORECARD = 'x_146833_idpkiro_u_idp_scorecard';
        this.TABLE_RULE = 'x_146833_idpkiro_u_idp_scorecard_rule';
        this.TABLE_RESULT = 'x_146833_idpkiro_u_idp_scorecard_result';
        this.CACHE_KEY = 'idp_scorecard_cache';
        this.CACHE_TTL = 300; // 5 minutes
    },

    /**
     * Calculate scorecard score for an entity
     * @param {String} scorecardId - The scorecard sys_id
     * @param {String} entityId - The entity being scored (service, app, etc.)
     * @returns {Object} - {score, results, passed, failed, warnings}
     */
    calculateScore: function(scorecardId, entityId) {
        if (!scorecardId || !entityId) {
            return {error: 'scorecardId and entityId are required'};
        }

        var results = [];
        var totalWeight = 0;
        var weightedScore = 0;

        // Get all active rules for this scorecard
        var rules = this.getRules(scorecardId);

        for (var i = 0; i < rules.length; i++) {
            var rule = rules[i];
            var result = this.evaluateRule(rule, entityId);

            // Store result
            this.storeResult(scorecardId, entityId, rule, result);

            results.push({
                rule: rule.name,
                category: rule.category,
                passed: result.passed,
                value: result.value,
                message: result.message,
                weight: rule.weight
            });

            // Calculate weighted score
            if (result.passed) {
                weightedScore += rule.weight;
            }
            totalWeight += rule.weight;
        }

        var finalScore = totalWeight > 0 ? Math.round((weightedScore / totalWeight) * 100) : 0;

        // Trigger auto-remediation if score drops below threshold
        if (finalScore < 70) {
            this.triggerRemediation(scorecardId, entityId, results);
        }

        return {
            score: finalScore,
            results: results,
            passed: results.filter(function(r) { return r.passed; }).length,
            failed: results.filter(function(r) { return !r.passed; }).length,
            warnings: results.filter(function(r) { return r.value === 'warning'; }).length
        };
    },

    /**
     * Evaluate a single rule against an entity
     */
    evaluateRule: function(rule, entityId) {
        var result = {
            passed: false,
            value: 0,
            message: ''
        };

        try {
            // Execute the rule script
            var evaluator = new Function('entityId', 'gs', 
                'return (function() { ' + rule.evaluation_script + ' })();'
            );
            result = evaluator(entityId, gs);
        } catch (e) {
            result.passed = false;
            result.message = 'Rule evaluation error: ' + e.message;
            gs.error('Scorecard rule evaluation failed: ' + e.message);
        }

        return result;
    },

    /**
     * Get all active rules for a scorecard
     */
    getRules: function(scorecardId) {
        var rules = [];
        var gr = new GlideRecord(this.TABLE_RULE);
        gr.addQuery('scorecard', scorecardId);
        gr.addQuery('active', true);
        gr.orderBy('category');
        gr.orderBy('order');
        gr.query();

        while (gr.next()) {
            rules.push({
                sys_id: gr.sys_id.toString(),
                name: gr.name.toString(),
                category: gr.category.toString(),
                description: gr.description.toString(),
                weight: parseFloat(gr.weight) || 1,
                evaluation_script: gr.evaluation_script.toString(),
                remediation_script: gr.remediation_script.toString(),
                order: parseInt(gr.order) || 0
            });
        }

        return rules;
    },

    /**
     * Store evaluation result
     */
    storeResult: function(scorecardId, entityId, rule, result) {
        var gr = new GlideRecord(this.TABLE_RESULT);
        gr.initialize();
        gr.setValue('scorecard', scorecardId);
        gr.setValue('entity_id', entityId);
        gr.setValue('rule', rule.sys_id);
        gr.setValue('rule_name', rule.name);
        gr.setValue('category', rule.category);
        gr.setValue('result_value', result.passed ? 1 : 0);
        gr.setValue('result_message', result.message || '');
        gr.setValue('evaluated_on', new GlideDateTime());
        gr.insert();
    },

    /**
     * Create DORA metrics scorecard
     */
    createDORAScorecard: function(teamId) {
        var gr = new GlideRecord(this.TABLE_SCORECARD);
        gr.initialize();
        gr.setValue('name', 'DORA Metrics - Team ' + teamId);
        gr.setValue('scorecard_type', 'dora');
        gr.setValue('entity_type', 'team');
        gr.setValue('entity_id', teamId);
        gr.setValue('description', 'DORA metrics tracking: Deployment Frequency, Lead Time, MTTR, Change Failure Rate');
        gr.setValue('target_score', 80);
        gr.setValue('active', true);
        var scorecardId = gr.insert();

        // Add DORA rules
        this.addDORARules(scorecardId);

        return scorecardId;
    },

    /**
     * Add standard DORA rules to a scorecard
     */
    addDORARules: function(scorecardId) {
        var doraRules = [
            {
                name: 'Deployment Frequency - High',
                category: 'dora_deployment_frequency',
                description: 'Deploy at least once per day (elite performer)',
                weight: 2,
                evaluation_script: 'var depCount = new GlideAggregate("change_request"); depCount.addQuery("type", "standard"); depCount.addQuery("cmdb_ci", entityId); depCount.addQuery("sys_created_on", ">=", gs.daysAgo(7)); depCount.addAggregate("COUNT"); depCount.query(); var count = depCount.next() ? parseInt(depCount.getAggregate("COUNT")) : 0; return { passed: count >= 7, value: count, message: count + " deployments in last 7 days" };'
            },
            {
                name: 'Lead Time for Changes - Low',
                category: 'dora_lead_time',
                description: 'Lead time less than 1 day (elite performer)',
                weight: 2,
                evaluation_script: 'var avgLeadTime = 0; // Would query pipeline metrics; return { passed: avgLeadTime <= 24, value: avgLeadTime, message: "Average lead time: " + avgLeadTime + " hours" };'
            },
            {
                name: 'MTTR - Low',
                category: 'dora_mttr',
                description: 'Mean time to recovery less than 1 hour',
                weight: 2,
                evaluation_script: 'var mttr = 0; // Would query incident metrics; return { passed: mttr <= 60, value: mttr, message: "MTTR: " + mttr + " minutes" };'
            },
            {
                name: 'Change Failure Rate - Low',
                category: 'dora_change_failure',
                description: 'Change failure rate less than 15%',
                weight: 2,
                evaluation_script: 'var failureRate = 0; // Would query deployment failures; return { passed: failureRate <= 15, value: failureRate, message: "Failure rate: " + failureRate + "%" };'
            }
        ];

        for (var i = 0; i < doraRules.length; i++) {
            var gr = new GlideRecord(this.TABLE_RULE);
            gr.initialize();
            gr.setValue('scorecard', scorecardId);
            gr.setValue('name', doraRules[i].name);
            gr.setValue('category', doraRules[i].category);
            gr.setValue('description', doraRules[i].description);
            gr.setValue('weight', doraRules[i].weight);
            gr.setValue('evaluation_script', doraRules[i].evaluation_script);
            gr.setValue('order', i + 1);
            gr.setValue('active', true);
            gr.insert();
        }
    },

    /**
     * Create Production Readiness scorecard
     */
    createProductionReadinessScorecard: function(serviceId) {
        var gr = new GlideRecord(this.TABLE_SCORECARD);
        gr.initialize();
        gr.setValue('name', 'Production Readiness');
        gr.setValue('scorecard_type', 'production_readiness');
        gr.setValue('entity_type', 'service');
        gr.setValue('entity_id', serviceId);
        gr.setValue('description', 'Production readiness checklist for services');
        gr.setValue('target_score', 90);
        gr.setValue('active', true);
        var scorecardId = gr.insert();

        // Add production readiness rules
        this.addProductionReadinessRules(scorecardId);

        return scorecardId;
    },

    /**
     * Add production readiness rules
     */
    addProductionReadinessRules: function(scorecardId) {
        var rules = [
            {
                name: 'Has Documentation',
                category: 'documentation',
                description: 'Service has up-to-date documentation',
                weight: 1,
                evaluation_script: 'var doc = new GlideRecord("kb_knowledge"); doc.addQuery("kb_category.title", "Service Documentation"); doc.addQuery("short_description", "CONTAINS", entityId); doc.query(); return { passed: doc.hasNext(), value: doc.getRowCount(), message: doc.hasNext() ? "Documentation exists" : "No documentation found" };'
            },
            {
                name: 'Has Monitoring',
                category: 'observability',
                description: 'Service has monitoring and alerting configured',
                weight: 2,
                evaluation_script: 'var alerts = new GlideAggregate("em_alert"); alerts.addQuery("cmdb_ci", entityId); alerts.addAggregate("COUNT"); alerts.query(); var count = alerts.next() ? parseInt(alerts.getAggregate("COUNT")) : 0; return { passed: count > 0, value: count, message: count + " alerts configured" };'
            },
            {
                name: 'Has On-Call Rotation',
                category: 'reliability',
                description: 'Service has on-call rotation defined',
                weight: 2,
                evaluation_script: 'var rota = new GlideRecord("cmn_rota"); rota.addQuery("cmdb_ci", entityId); rota.query(); return { passed: rota.hasNext(), value: rota.getRowCount(), message: rota.hasNext() ? "On-call configured" : "No on-call rotation" };'
            },
            {
                name: 'Has DR Plan',
                category: 'disaster_recovery',
                description: 'Service has disaster recovery plan',
                weight: 2,
                evaluation_script: 'var dr = new GlideRecord("dr_plan"); dr.addQuery("service", entityId); dr.query(); return { passed: dr.hasNext(), value: dr.getRowCount(), message: dr.hasNext() ? "DR plan exists" : "No DR plan" };'
            },
            {
                name: 'Security Review Complete',
                category: 'security',
                description: 'Service has passed security review',
                weight: 3,
                evaluation_script: 'var review = new GlideRecord("sn_sec_review"); review.addQuery("service", entityId); review.addQuery("state", "completed"); review.query(); return { passed: review.hasNext(), value: review.getRowCount(), message: review.hasNext() ? "Security review passed" : "Security review pending" };'
            }
        ];

        for (var i = 0; i < rules.length; i++) {
            var gr = new GlideRecord(this.TABLE_RULE);
            gr.initialize();
            gr.setValue('scorecard', scorecardId);
            gr.setValue('name', rules[i].name);
            gr.setValue('category', rules[i].category);
            gr.setValue('description', rules[i].description);
            gr.setValue('weight', rules[i].weight);
            gr.setValue('evaluation_script', rules[i].evaluation_script);
            gr.setValue('order', i + 1);
            gr.setValue('active', true);
            gr.insert();
        }
    },

    /**
     * Trigger auto-remediation when score drops
     */
    triggerRemediation: function(scorecardId, entityId, results) {
        var failedRules = results.filter(function(r) { return !r.passed; });

        for (var i = 0; i < failedRules.length; i++) {
            var rule = this.getRuleByName(failedRules[i].rule);
            if (rule && rule.remediation_script) {
                try {
                    var remediate = new Function('entityId', 'gs', rule.remediation_script);
                    remediate(entityId, gs);
                    gs.info('Auto-remediation executed for rule: ' + rule.name);
                } catch (e) {
                    gs.error('Auto-remediation failed for ' + rule.name + ': ' + e.message);
                }
            }
        }

        // Create notification/notify owning team
        this.notifyTeam(scorecardId, entityId, results);
    },

    /**
     * Get rule by name
     */
    getRuleByName: function(ruleName) {
        var gr = new GlideRecord(this.TABLE_RULE);
        gr.addQuery('name', ruleName);
        gr.query();
        if (gr.next()) {
            return {
                sys_id: gr.sys_id.toString(),
                name: gr.name.toString(),
                remediation_script: gr.remediation_script.toString()
            };
        }
        return null;
    },

    /**
     * Notify team about scorecard drop
     */
    notifyTeam: function(scorecardId, entityId, results) {
        var scorecard = new GlideRecord(this.TABLE_SCORECARD);
        if (scorecard.get(scorecardId)) {
            var event = gs.eventQueue('idp.scorecard.dropped', scorecard, 
                JSON.stringify({
                    entityId: entityId,
                    scorecardName: scorecard.name.toString(),
                    failedRules: results.filter(function(r) { return !r.passed; }).map(function(r) { return r.rule; })
                }), 
                scorecard.getValue('owner'));
        }
    },

    /**
     * Get all scorecards for an entity
     */
    getScorecardsForEntity: function(entityId) {
        var scorecards = [];
        var gr = new GlideRecord(this.TABLE_SCORECARD);
        gr.addQuery('entity_id', entityId);
        gr.addQuery('active', true);
        gr.query();

        while (gr.next()) {
            scorecards.push({
                sys_id: gr.sys_id.toString(),
                name: gr.name.toString(),
                type: gr.scorecard_type.toString(),
                score: this.getLatestScore(gr.sys_id.toString(), entityId),
                target: parseInt(gr.target_score) || 80
            });
        }

        return scorecards;
    },

    /**
     * Get latest score for a scorecard
     */
    getLatestScore: function(scorecardId, entityId) {
        var latestScore = 0;
        var gr = new GlideAggregate(this.TABLE_RESULT);
        gr.addQuery('scorecard', scorecardId);
        gr.addQuery('entity_id', entityId);
        gr.addAggregate('AVG', 'result_value');
        gr.query();

        if (gr.next()) {
            latestScore = Math.round(parseFloat(gr.getAggregate('AVG', 'result_value')) * 100);
        }

        return latestScore;
    },

    type: 'IDPScorecardEngine'
};
